/* --- wave86s: lazy grade10 subject chunk: prob --- */
(function(){
  if(String(window.GRADE_NUM || '') !== '10') return;
  const PRB_TH={classic:'<h3>Классическая вероятность</h3>\n<p><b>Формула:</b> P = благоприятные исходы / все исходы</p>\n<p><b>Сколько исходов?</b></p>\n<ul><li>Монета: 2 (орёл, решка)</li>\n<li>Кубик: 6 (числа 1–6)</li>\n<li>Два кубика: 36 (6×6)</li>\n<li>Шары в мешке: сколько шаров, столько и исходов</li></ul>\n<div class="ex">В мешке 3 красных и 7 синих = 10 шаров. P(красный) = 3/10<br>Кубик, P(чётное) = 3/6 = 1/2 (чётные: 2, 4, 6 — три штуки)</div>\n<p><b>Дроби сокращай:</b> 4/6 = 2/3, 3/9 = 1/3</p>',comb:'<h3>Комбинаторика</h3>\n<p><b>Факториал n!</b> = 1·2·3·…·n (произведение всех чисел от 1 до n)</p>\n<div class="fm">3! = 6,  4! = 24,  5! = 120,  6! = 720,  7! = 5040</div>\n<p><b>Сочетания C(n,k)</b> — сколькими способами выбрать k из n (порядок не важен):</p>\n<div class="fm">C(n,k) = n! / (k! · (n−k)!)</div>\n<div class="ex">C(5,2) = 5!/(2!·3!) = 120/(2·6) = 10 — 10 способов выбрать 2 из 5</div>\n<p><b>Размещения A(n,k)</b> — порядок важен: A(n,k) = n!/(n−k)!</p>',stats:"<h3>Статистика</h3>\n<p>Дан ряд чисел, например: 2, 5, 3, 8, 7</p>\n<ul><li><b>Среднее</b> = сумма / количество = (2+5+3+8+7)/5 = 5</li>\n<li><b>Медиана</b> = средний элемент (сначала отсортируй!): 2,3,5,7,8 → медиана = 5</li>\n<li><b>Мода</b> = самое частое значение (в 2,3,3,5,8 мода = 3)</li>\n<li><b>Размах</b> = max − min = 8 − 2 = 6</li></ul>"};function genPClass(){const o=pick([()=>{const o=pick(range(1,6)),a=7-o,e=gcd(a,6);return[`Бросают кубик. Какова вероятность выпадения числа ≥${o}?`,a/e+"/"+6/e,"Благоприятных: "+a+" из 6"]},()=>{const o=pick(range(1,8)),a=pick(range(1,8)),e=o+a,n=gcd(o,e);return[`В мешке ${o} красных и ${a} синих шаров. Наугад достают один. P(красный)=?`,o/n+"/"+e/n,"P="+o+"/"+e]},()=>{const o=pick(range(1,6)),a=pick(range(1,6)),e=pick(range(1,4)),n=o+a+e,t=gcd(o,n);return[`В коробке ${o} красных, ${a} синих и ${e} зелёных шаров. Наугад берут один. P(красный)=?`,o/t+"/"+n/t,"P="+o+"/"+n]},()=>{const o=pick(range(10,30)),a=pick(range(1,o-1)),e=gcd(a,o);return[`В классе ${o} учеников, из них ${a} отличников. Наугад выбирают одного. P(отличник)=?`,a/e+"/"+o/e,"P="+a+"/"+o]},()=>{const o=pick([2,3,4,5]),a=Math.floor(6/o),e=gcd(a,6);return[`Бросают кубик. Какова вероятность, что число делится на ${o} без остатка?`,a/e+"/"+6/e,"Делятся на "+o+" без остатка: "+a+" шт."]}])(),a=()=>{const a=o[1].split("/");return 2===a.length?Math.max(1,+a[0]+pick([-1,1,2]))+"/"+a[1]:"?"};return mkQ(o[0],o[1],fillW(o[1],[a,a,a]),o[2],"Вероятность","#16a34a","#dcfce7")}function genPComb(){const o=pick([()=>{const o=pick(range(3,8));let a=1;for(let e=2;e<=o;e++)a*=e;return[`${o}!=?`,""+a,range(1,o).join("·")]},()=>{const o=pick(range(4,12)),a=pick(range(2,4));if(a>=o)return["C(5,2)=?","10","5!/(2!3!)"];let e=1,n=1;for(let t=0;t<a;t++)e*=o-t,n*=t+1;return[`C(${o},${a})=?`,""+e/n,"n!/(k!(n-k)!)"]},()=>{const o=pick(range(3,7)),a=pick(range(2,4));if(a>=o)return["A(5,2)=?","20","5!/3!"];let e=1;for(let n=0;n<a;n++)e*=o-n;return[`A(${o},${a})=?`,""+e,"n!/(n-k)!"]}])(),a=+o[1],e=()=>""+Math.max(1,a+pick([-3,-2,1,2,5,10]));return mkQ(o[0],o[1],fillW(o[1],[e,e,e]),o[2],"Комбинаторика","#2563eb","#dbeafe")}function genPStats(){const o=shuffle(range(1,15)).slice(0,5).sort((o,a)=>o-a),a=pick([()=>{const a=o.reduce((o,a)=>o+a,0)/5;return[`${o.join(",")}. Среднее=?`,a%1?a.toFixed(1):""+a,"Σ/n"]},()=>[`${o.join(",")}. Медиана=?`,""+o[2],"Средний элемент"],()=>[`${o.join(",")}. Размах=?`,""+(o[4]-o[0]),"max−min"]])(),e=parseFloat(a[1]),n=()=>{let o;do{o=Math.round(10*(e+pick([-3,-1,1,2])))/10}while(o===e);return o%1?o.toFixed(1):""+o};return mkQ(a[0],a[1],fillW(a[1],[n,n,n]),a[2],"Статистика","#ea580c","#fff7ed")}
  if(typeof window.__wave86sApplyGrade10Subject === 'function'){
    window.__wave86sApplyGrade10Subject("prob", { topics:[
      {id:"classic",nm:"Классическая P",gen:genPClass,th:PRB_TH.classic,dot:"#16a34a"},
      {id:"comb",nm:"Комбинаторика",gen:genPComb,th:PRB_TH.comb,dot:"#2563eb"},
      {id:"stats",nm:"Статистика",gen:genPStats,th:PRB_TH.stats,dot:"#ea580c"}
    ] });
  }
})();
